let validToken = "";

try {
  // Coba ambil token baru (jika lewat jalur get new token)
  validToken = $("Get New KC Token").first().json.access_token;
} catch (error) {
  // Jika error (karena node tidak dieksekusi), ambil token lama dari DB
  validToken = $("Read Existing Token").first().json.token;
}

const webhook = $("Knox JIT Webhook").first().json.body;
const config = $("Global Config").first().json;

for (const item of $input.all()) {
  item.json.token = validToken;
  item.json.role_name = webhook.access_type + ":" + webhook.workflow_id;
  item.json.user_email = webhook.user_requestor;
  item.json.client_name = config.KEYCLOAK_CLIENT_NAME;
  item.json.realm = config.KEYCLOAK_ADMIN_REALM;
  item.json.kc_url = config.KEYCLOAK_URL;
}

return $input.all();

